var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"죄수 이송용 승강궤도- 특수무기징역수 올리비에 콜먼.","JPN":"囚人移送用の昇降軌道 - 特殊無期懲役囚、オリヴィエ・コールマン。","ENG":"Prisoner Transfer Elevation Tracks - Special Life Sentence Prisoner: Olivie Coleman.","TWN":"用於押送囚犯的軌道升降機——特殊武器罪犯奧利維亞·科曼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"챔버 도시관리국 관할 우주정거장 교도소, 아케론 입소 전.","JPN":"チェンバー都市管理局管轄の宇宙ステーション刑務所、アケロンの入所前。","ENG":"Before entering Acheron, the Chamber City Management Jurisdiction Space Station Penitentiary.","TWN":"強巴城市管理局管轄的太空站，黃泉入監前。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"여기는 G플랫폼. 수용 절차를 마친 죄수가 승강궤도에 탑승합니다.","JPN":"こちら、プラットフォームG。収容手続きを終えた囚人が、昇降軌道に搭乗します。","ENG":"Calling from Platform G. The prisoner completed her admittance procedure and is stepping aboard the elevation tracks.","TWN":"這裡是G平台，完成收監程序的囚犯將登上軌道升降機。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"확인했습니다. 죄수 이송을 위해 G플랫폼의 아케론 승강궤도 진입을 허가합니다.","JPN":"確認しました。囚人移送のため、プラットフォームGのアケロン昇降軌道進入を許可します。","ENG":"Confirmed. Granting access to Platform G's Acheron elevation tracks for prisoner transfer.","TWN":"已確認，授權G平台為押送囚犯進入黃泉軌道升降機。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L11_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"어지간한 범죄로는 큐브까지 올 일은 없을 텐데, 꼬맹이가 아주 엄청난 짓을 저질렀나보군.","JPN":"中途半端な犯罪ならキューブまで来ないはずだ。チビのくせにとんでもねえことをしでかしたんだな。","ENG":"No ordinary crime would get you all the way to the cube. The kid must've done something huge.","TWN":"竟然被送到了魔方，這小鬼肯定幹了什麼驚天動地的大事。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"법정 경비원한테 듣기론 자기가 속해 있던 태스크포스를 돈 때문에 배신했다고 하던데.","JPN":"法廷の警備員に聞いたんだが、所属していたタスクフォースを金のために裏切ったらしいぞ。","ENG":"A court guard told me she betrayed her own TASKFORCE for money.","TWN":"法院保全說她為了錢背叛了自己所屬的特遣勢力。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"작전지역에서 대원들을 버리고 떠난 것도 모자라 회사 건물을 주먹으로 부쉈다 봐.","JPN":"作戦地域で隊員を捨てた上に、会社のビルを拳で破壊したとか。","ENG":"Not only did she abandon her troops and run away from the operation area, but she also punched the company building until it collapsed.","TWN":"她不僅在戰區拋棄了自己的隊員們，還用拳頭破壞了公司的大樓。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관리자님의 계획대로라면, 스승님께선 위조된 죄수 신분으로 무사히 아케론 수감소에 들어가실 수 있을 겁니다.","JPN":"管理者さんの計画どおりなら、師匠は偽造した囚人の身分で無事アケロン収容所まで入れるはずです。","ENG":"According to the Administrator's plan, you should be able to enter Acheron Penitentiary as a fake prisoner without any problems.","TWN":"如果管理者的計畫順利進行，師父應該能以偽造囚犯的身分順利進入黃泉收押所。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"알겠다.","JPN":"了解した。","ENG":"Understood.","TWN":"知道了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 녀석 계획이란 건 마음에 안 들지만 어쩔 수 없지.","JPN":"あいつの計画というのは気に入らないが、仕方ない。","ENG":"I'm not happy with the fact that it was his plan, but I guess I have no choice.","TWN":"雖然不喜歡他的計畫，但沒辦法了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"죄수 이송 목적 외에는 결코 문을 열지 않는 감옥입니다. 기회는 단 한 번이에요.","JPN":"囚人移送の目的以外には、決して扉を開かない監獄です。チャンスはこの一度だけですよ。","ENG":"The prison never opens its gates for purposes other than prisoner transfers. You only have one opportunity.","TWN":"這個監獄的大門只會為押送囚犯的用途打開，機會只有一次。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 아케론에 도착하기 전까진 절대, 소란을 피워서 일을 망치시면 안 됩니다.","JPN":"ですから、アケロンに着くまでは絶対、騒ぎを起こして気づかれないようにしてください。","ENG":"So whatever happens, do not attract any attention to yourself and mess this up until you arrive at Acheron.","TWN":"所以在抵達黃泉之前，千萬不要引起騷亂。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"쓸데없는 걱정이군. 그럴 일은 없을 거다.","JPN":"杞憂だな。","ENG":"No need to worry. That won't happen.","TWN":"別擔心，不會發生這種事。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"이런 꼬맹이가 주먹으로 건물을 부쉈다고?","JPN":"こんなチビが、拳でビルを破壊しただと？","ENG":"This kid made a building collapse with her fists?","TWN":"這孩子用拳頭破壞了一棟樓？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L28_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"그보다 무서운 건 진상을 확인하러 온 관리국 직원들도 무자비하게 공격했단 거야.","JPN":"もっと怖いのは、確認しに来た管理局の職員も無惨にやられたそうだ。","ENG":"Even worse, they said she attacked the Administration employees who had gone to investigate what was happening.","TWN":"甚至還攻擊了那些前來調查情況的管理局員工。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"미안하다고 사과하면서 계속 두들겨 팼다더라고.","JPN":"すまないって言いながら殴り続けたらしい。","ENG":"Apparently, she beat them up while saying sorry.","TWN":"據說是邊道歉邊毆打。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"우왓, 그거 완전 사이코패스잖아?!","JPN":"うわっ、それ完全にサイコパスじゃねえかよ！？","ENG":"Whoa, that's some psychopath behavior!","TWN":"哇，那豈不是神經病？！"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"판사도 그 점에서 아연실색하며 아케론행 판결을 내렸다는군.","JPN":"判事もそれを聞いて驚愕し、アケロン行きの判決を出したそうだ。","ENG":"Seems like the judge was also shocked by that, deciding to send her to Acheron.","TWN":"法官也對此感到震驚，做出了把她押送到黃泉的判決。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"꼬맹이가 인상만 더러운 게 아니라 아주 막 나가는 괴물이었구만.","JPN":"このチビ、印象が悪いだけかと思いきや、とんでもない化け物だったんだな。","ENG":"This kid has more than just nasty looks. She's a reckless monster.","TWN":"這小鬼果真是個可怕的怪物。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_FAKE","face":"UNIT_DESPAIR"},"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"그러게나 말이야. 이런 지독한 악인이 하필이면 훌륭한 과학자이신 올리비에 박 교수님과 같은 이름을 쓰다니. 기분 나쁘구만.","JPN":"本当だぜ。こんな悪人がよりによって誉れ高き科学者、オリヴィエ・ナツキ教授と同じ名前だなんて。気持ちわりぃ。","ENG":"Yeah. I can't believe this crook has the same name as the venerated scientist, Professor Olivie Park. It's almost disgusting.","TWN":"就是啊。如此惡人的名字竟然和那偉大的科學家奧利維亞一模一樣，真是噁心啊。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_FAKE","face":"UNIT_DESPAIR"},"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_FAKE","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_FAKE","text":{"KOREA":"아.","JPN":"あ。","ENG":"Ah.","TWN":"啊。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"…응? 방금 뭔가 잘못되는 소리가 났는데?","JPN":"……あ？　今ヤバい音がしたぞ？","ENG":"...Hmm? I just heard something go wrong.","TWN":"……唉？剛剛聽到了奇怪的聲音？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"이, 이 녀석! 카운터 구속 수갑을 부러트렸어!","JPN":"こ、こいつ！　カウンター拘束用の手錠を壊しやがった！","ENG":"W-what?! She just broke the Counter-restraining handcuffs!","TWN":"這、這傢伙！把制裁者約束手銬弄斷了！"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_FAKE","text":{"KOREA":"…팔에 힘이 너무 들어갔다. 미안하게 됐군.","JPN":"……少し力んでしまった。悪いな。","ENG":"...I didn't mean to pull that hard. Sorry.","TWN":"……我的手臂用力過猛了。對不起。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_FAKE","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"히익! 저 녀석, 방금 우리에게 사과했어!","JPN":"ひいっ！　あいつ、今俺らに謝ったぞ！","ENG":"Eek! She just, apologized, to us!","TWN":"啊啊！她剛剛向我們道歉了！"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"어쩌지?! 이제 저 주먹으로 우릴 두들겨 팰 셈인 건가?!","JPN":"どうする！？　これからあの拳で俺たちボコボコにされるのか！？","ENG":"What do we do?! Is she going to beat us up with those fists?!","TWN":"怎麼辦？！她會用那雙拳頭把我們打死嗎？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_FAKE","text":{"KOREA":"…아니. 일부러 그런 게 아니라니까.","JPN":"……いや。わざとではない。","ENG":"...Wait. I really didn't mean to.","TWN":"……不，我不是故意的。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"으아아아아!! 제압해! 제압하라고!","JPN":"うわあああ！！　制圧！　制圧しろ！","ENG":"AAAAH!!!! Take her down! Take her down!!!","TWN":"呃啊啊啊啊！快制伏！快點！"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"뭐하는 거야! 개머리판으로 후려친다고 이 괴물한테 통하겠어?!","JPN":"何やってんだ！　ストックで叩くなんて、この化け物に通用するわけねえだろ！？","ENG":"What are you doing?! Hitting her with the gun won't work on a monster like her!","TWN":"你在幹什麼！你覺得用槍托能制伏她嗎？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_FAKE","text":{"KOREA":"큭…! 크으윽…!","JPN":"くっ……！　くううっ……！","ENG":"Kgh...! Kghhh...!","TWN":"咳……！呃呃……！"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_FAKE","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"…쓰러졌어?","JPN":"……倒れた？","ENG":"...She's down?","TWN":"……倒下了？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"어떻게 된 거지?","JPN":"どういうことだ？","ENG":"What happened?","TWN":"怎麼回事？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"여기는 아케론 컨트롤타워. 방금 CRF 반응이 감지됐는데, 승강기에 무슨 일이 있습니까?","JPN":"こちら、アケロンコントロールタワー。CRFの反応を感知しましたが、昇降機で問題でも起きましたか？","ENG":"This is Acheron Control Tower speaking. We just sensed some CRF responses. Did anything happen inside the elevator?","TWN":"這裡是黃泉控制塔。剛剛發現了CRF反應，電梯是不是出了什麼問題？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L23_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"…아, 별일 아닙니다. 죄수가 잠시 소동을 피워서 제압했습니다.","JPN":"……あ、大したことではありません。囚人が少し暴れましたが、制圧しました。","ENG":"...Oh, it was nothing. The prisoner was acting up, so we subdued her.","TWN":"……啊，沒什麼。囚犯想要鬧事，已經被我們控制住了。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇군요. 도착하는대로 격리 조치하겠습니다.","JPN":"そうですか。では到着次第、隔離措置します。","ENG":"I see. We will have her quarantined as soon as she arrives.","TWN":"好的，抵達後我們就馬上隔離。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"승강기 회선이 불량해서 모니터링이 어려우니 문제가 생기면 바로 비상벨을 누르십시오.","JPN":"昇降機の回線が故障しモニタリングが上手くいかないので、問題が生じれば直ちに非常ベルで知らせてください。","ENG":"The elevator's communication lines are faulty, making it difficult to monitor the situation. You are to immediately press the emergency button upon any issues.","TWN":"目前電梯線路不暢，無法即時監控，因此如果出現問題就請立即按下緊急鈴。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"휴우, 십년감수했군.","JPN":"ふう、死ぬかと思ったぜ。","ENG":"Phew. That was close.","TWN":"呼，嚇我一跳。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"이거 봐. 구속장치가 두 동강 났어.","JPN":"これ、見ろよ。拘束装置が真っ二つだ。","ENG":"Look. The restraints broke in two.","TWN":"你看，這個約束器被掰成兩段了。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"이 꼬맹이, 함선으로 들이받아도 못 부수는 이터니움 초합금을 어떻게 끊은 거지?","JPN":"このチビ、艦船がぶつかっても壊れないエタニウム超合金をどうやって切ったんだ？","ENG":"How did this kid break Eternium superalloy that's supposed to withstand a ship crash?","TWN":"嘿，小鬼。你是怎麼弄斷了這個連飛船都無法撞斷的永恆之金超合金？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"글쎄…","JPN":"さあ……","ENG":"I don't know...","TWN":"這個嘛……"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"낡아서 그런가?","JPN":"古いからか？","ENG":"Maybe it's really old?","TWN":"是不是因為它太破舊了？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"곧 죄수가 도착할 거다.","JPN":"もうすぐ囚人が到着する。","ENG":"The prisoner's about to arrive.","TWN":"囚犯馬上就會到達。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"교육 지침은 잘 숙지하고 있겠지, 헤이븐?","JPN":"教育指針は熟知しているだろうな？　ヘイブン。","ENG":"I expect you've familiarized yourself with the training guidelines, Haven.","TWN":"需要教導的內容還沒忘掉吧，天堂？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"맡겨주시죠. 신참은 제가 책임지고 가이드하도록 하겠습니다.","JPN":"任せてください。新入りは僕が責任をもってガイドします。","ENG":"Of course. I'll make sure to properly guide this newcomer.","TWN":"交給我吧。我會好好幫助新人的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"그래, 모범수인 자네에겐 직원들이 많이 의지하고 있어.","JPN":"ああ、模範囚である君には職員ともども頼りにしているぞ。","ENG":"Yeah. You're one of the best behaved here, so the employees are relying on you.","TWN":"好。員工們都非常依賴你這個模範囚犯。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"신참이 오자마자 승강기에서 문제를 일으켰다던데, 잘 좀 지도해주라고.","JPN":"新入りがさっそく、昇降機で問題を起こしたようだ。ちゃんと指導してくれよ。","ENG":"I heard the newbie caused some trouble in the elevator, so keep her in check.","TWN":"聽說新人在電梯裡鬧事了，希望你能好好教導。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"네, 걱정마세요.","JPN":"はい、ご心配なく。","ENG":"I will. Don't worry.","TWN":"好的，別擔心。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"아, 죄송하지만 이번 달도 고아원에 대리 기부를 부탁드려도 될까요?","JPN":"あ、そうだ。すみませんが、今月も孤児院に代理の寄付をお願いしてもいいですか？","ENG":"Oh, and I'm sorry, but will you donate my money to the orphanage again this month, please?","TWN":"對了，這個月也想麻煩你代為捐款給孤兒院，可以嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"그래, 걱정 말게.","JPN":"ああ、心配するな。","ENG":"Yeah. I'll take care of it.","TWN":"沒問題，別擔心。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"이번에도 무기명으로 보내는 건가? 그 사람들도 누가 보내는지 정도는 알아야 감사를 할 텐데.","JPN":"また無記名で送るのか？　あの人たちも誰からの寄付かわからないと、感謝したくてもできないだろうに。","ENG":"Do you want it to be anonymous again? They won't be able to thank you unless they know who sent it.","TWN":"這次也要匿名捐款嗎？我覺得他們也有必要知道是誰在幫助自己，這樣才能好好感謝你呀。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"감사 받을 일은 아닙니다. 가족이 진 빚을 마땅히 갚고 있는 거니까요.","JPN":"感謝されるようなことではありません。家族の借りを返しているだけですから。","ENG":"It's not something I should be thanked for. I'm just repaying what my family owed them.","TWN":"這不是值得收到感謝的事情，我只是在償還家人欠下的債。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"밖에서 복잡한 사정이 있었나보구만. 그 좋은 심성으로 고생이 많았겠어.","JPN":"外で複雑な事情があったみたいだな。君は優しいから、苦労したんだろう。","ENG":"I guess you had some complicated stuff going on out there. Would've been difficult with that heart of gold of yours.","TWN":"看來你在外面經歷了很多事，你心地這麼善良一定受了不少苦。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"하하…","JPN":"ハハ……","ENG":"Haha...","TWN":"哈哈……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"승강기가 도킹 포트에 진입했습니다.","JPN":"昇降機がドッキングポートに進入しました。","ENG":"The elevator reached its docking port.","TWN":"電梯預備停下。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"출입문을 개방합니다.","JPN":"ドアを開放します。","ENG":"Opening the gates.","TWN":"即將開門。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"이번에 오는 사람은 말이 잘 통하는 분이면 좋겠네요.","JPN":"今度来る人は、言葉が通じる人であってほしいですね。","ENG":"I hope this prisoner is reasonable.","TWN":"希望能和這次來的新人談得來。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"자네가 그렇게 말하면 항상 반대로 이뤄지는 징크스가 있단 말이지.","JPN":"君の言葉は、いつも反対になるジンクスがあるんだよ。","ENG":"I think you jinx it whenever you say that.","TWN":"你每次說這種話都會引來相反的後果。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"지난 번에 온 그 해괴한 옷차림의 죄수도 그렇고 말이야.","JPN":"前に来たあの変な服装の囚人もそうだった。","ENG":"Like when that last prisoner who was wearing those bizarre clothes arrived.","TWN":"比如上次那個奇怪打扮的囚犯。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"에이, 너무하세요.","JPN":"そんなことありませんよ。","ENG":"Oh, come on.","TWN":"哎呀，哪有啊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"하하, 농담이야- 농담-","JPN":"ハハ。冗談だよ、冗談。","ENG":"Haha, I'm just messing with you.","TWN":"哈哈，開個玩笑。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"비상! 죄수가 통제상황에서 벗어났다!","JPN":"非常状態！　囚人が統制状況から解かれた！","ENG":"Alert! The prisoner is no longer under control!","TWN":"緊急狀況！囚犯脫離控制了！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"프론트 구역을 전면 폐쇄해! 다른 수감동으로부터 분리시켜라!","JPN":"フロント区域を全面閉鎖しろ！　他の収容棟から分離するんだ！","ENG":"Close off the entire front area! Separate her from the other sections!","TWN":"封鎖前部區域！與其他牢房隔離！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"패러독스는 어디에 있지?","JPN":"パラドックスはどこにいる？","ENG":"Where's Paradox?","TWN":"悖論在哪裡？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"그… 그게 무슨 소리지? 패러독스가 뭐야?","JPN":"パ……パラドックス？　何を言っているんだ？","ENG":"W-what do you mean? What do you mean, \\"paradox?\\"","TWN":"什……什麼意思？什麼是悖論？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"잡아뗄 거 없다. 그 여자가 이곳에 수감되어 있다는 사실은 알고 왔으니까.","JPN":"とぼけるな。あの女がここに収容されているのは知っているぞ。","ENG":"Don't act stupid. I know she's held in this prison.","TWN":"別裝蒜了。我知道她被關在這裡。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"나, 난 정말로 몰라. 아케론에는 별도로 관리되는 보안구역이 한 두 곳이 아니라고.","JPN":"お、俺は本当に知らない。アケロンには、別々に管理されている保安区域が多いんだ。","ENG":"I-I really don't know. Acheron holds multiple security areas that are separately managed.","TWN":"我，我真的不知道。黃泉有很多單獨管理的保安區域。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그러냐?","JPN":"そうか。","ENG":"Is that so?","TWN":"是嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"전부 털고 다니려면 시간 좀 걸리겠군.","JPN":"すべて探し出すには時間がかかりそうだな。","ENG":"It'll take some time for me to go through all of them, then.","TWN":"那麼全部調查需要花不少時間。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그 손 놓으십시오.","JPN":"その手を放してください。","ENG":"Let that hand go.","TWN":"把手拿開。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"범죄자로 살다가 이런 곳까지 와서도 행패를 부리는 겁니까?","JPN":"犯罪者として生きてきて、ここに来てもなお罪を重ねるつもりですか？","ENG":"You'd cause trouble in a penitentiary, even after all that time as a criminal?","TWN":"你這個罪犯被關進這裡了還要撒野嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"넌 뭐지? 간수치곤 뺀질뺀질하게 생겼군.","JPN":"お前はなんだ？　看守の割には不真面目な顔をしているな。","ENG":"What are you? You look too pretty to be a guard.","TWN":"你是什麼人？你長得可不像獄警。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"일단은 죄수 신분입니다만, 이곳의 죄수들이 모두 당신처럼 폭동을 바라는 건 아닙니다.","JPN":"僕も囚人です。ですがここの囚人がみんなあなたのように暴動を望んでいるわけではありません。","ENG":"I am technically a prisoner, but not all prisoners want to riot, like you.","TWN":"我也是囚犯。並不是所有囚犯都像你一樣想要引發暴動。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그러니 우선 당신을 제압하겠어요.","JPN":"なので、まずはあなたを制圧します。","ENG":"So I'm going to have to subdue you first.","TWN":"所以我要先制伏你。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};